function countPairs(nums, k) {
  // For each x in nums, we want to know how many earlier elements equal k - x.
  // Maintain a Map<value, count> of values seen so far.
  // For each new nums[i]:
  //   1. answer += (count of k - nums[i] in map)
  //   2. increment count of nums[i] in map
}

solution:
// O(n) time, O(n) space.
function countPairs(nums, k) {
  const counts = new Map();
  let pairs = 0;
  for (const x of nums) {
    const need = k - x;
    pairs += counts.get(need) || 0;
    counts.set(x, (counts.get(x) || 0) + 1);
  }
  return pairs;
}
